module lfsr (
    input rst_clk,
    input reset,
    output reg [4:0] lfsr
);

    always @(posedge rst_clk or posedge reset) begin
        if (reset) begin
            lfsr <= 5'b00001;
        end else begin
            lfsr <= {lfsr[3:0], lfsr[4] ^ lfsr[2]};
        end
    end
endmodule
